const raw = $input.first().json || {};
const now = new Date().toISOString();
const pdfPath = String(raw.pdf_path || raw.path || raw.file_path || raw.caminho || '').trim();
const fileName = String(raw.file_name || raw.filename || pdfPath.split(/[\\/]/).pop() || 'documento.pdf').trim();
const source = String(raw.source || raw.origem || 'n8n-webhook').trim();
const requestId = raw.request_id || `pdf_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
return [{ json: { request_id: requestId, received_at: now, pdf_path: pdfPath, file_name: fileName, source, raw_keys: Object.keys(raw), status: 'normalized' } }];

const item = $input.first().json;
const flags = [];
let ok = true;
if (!item.pdf_path) { ok = false; flags.push('sem_caminho_pdf'); }
if (!item.file_name.toLowerCase().endsWith('.pdf') && !item.pdf_path.toLowerCase().endsWith('.pdf')) { ok = false; flags.push('nao_pdf'); }
const underDrop = item.pdf_path.replace(/\\/g, '/').includes('00_Inbox/pdfs/');
if (!underDrop) flags.push('fora_do_drop_folder_recomendado');
return [{ json: { ...item, ok, flags, permission: ok ? 'trigger_only' : 'blocked', status: ok ? 'validated' : 'blocked' } }];

const item = $input.first().json;
const event = {
  event_id: item.request_id,
  detected_at: item.received_at,
  status: item.status,
  source: item.source,
  source_pdf: item.pdf_path,
  file_name: item.file_name,
  target_agent: 'claude.documentalista',
  spec: '60_Sistemas/FabioOS/specs/2026-06-30_pipeline-pdf-aprende.md',
  next_action: 'Executar watcher local ou entregar caminho ao documentalista quando Stirling estiver autenticado.',
  safety: {
    ocr_executed: false,
    rag_reindexed: false,
    content_copied: false,
    requires_sensitive_data_gate: true,
    requires_human_curation_before_rag: true
  }
};
return [{ json: { ...item, drop_event: event, status: item.ok ? 'event_ready' : 'blocked' } }];
